// Collect all resources from paginated responses
const allResources = [];

for (const item of $input.all()) {
  const bundle = item.json;
  if (bundle.entry) {
    bundle.entry.forEach(entry => {
      if (entry.resource) {
        allResources.push(entry.resource);
      }
    });
  }
}

// Return as individual items for processing
return allResources.map(resource => ({ json: resource }));

const resource = $input.item.json;
const practice = $('Process Each Practice').item.json;

// Add IPA-specific metadata
resource.meta = resource.meta || {};
resource.meta.tag = resource.meta.tag || [];
resource.meta.tag.push({
  system: 'http://vpn.example.com/practice',
  code: practice.id,
  display: practice.name
});

// Prefix resource ID with practice ID for uniqueness across IPA
resource.id = `${practice.id}-${resource.id}`;

// Add extension for practice attribution
resource.extension = resource.extension || [];
resource.extension.push({
  url: 'http://hdim.com/fhir/StructureDefinition/attributed-practice',
  valueReference: {
    reference: `Organization/${practice.id}`,
    display: practice.name
  }
});

return { json: resource };

const resources = $input.all().map(item => item.json);
const practice = $('Process Each Practice').item.json;

// Split into batches of 100
const BATCH_SIZE = 100;
const batches = [];

for (let i = 0; i < resources.length; i += BATCH_SIZE) {
  const batchResources = resources.slice(i, i + BATCH_SIZE);

  const bundle = {
    resourceType: 'Bundle',
    type: 'batch',
    timestamp: new Date().toISOString(),
    meta: {
      tag: [{
        system: 'http://vpn.example.com/sync',
        code: 'athena-fhir',
        display: `athenahealth sync for ${practice.name}`
      }]
    },
    entry: batchResources.map(resource => ({
      fullUrl: `urn:uuid:${resource.id}`,
      resource: resource,
      request: {
        method: 'PUT',
        url: `${resource.resourceType}/${resource.id}`
      }
    }))
  };

  batches.push({ json: bundle });
}

console.log(`Practice ${practice.id}: Created ${batches.length} bundles from ${resources.length} resources`);
return batches;

const practice = $('Process Each Practice').item.json;
const uploadResults = $input.all();

const logEntry = {
  timestamp: new Date().toISOString(),
  workflow: 'IPA athena FHIR Sync',
  practiceId: practice.id,
  practiceName: practice.name,
  bundlesUploaded: uploadResults.length,
  status: 'SUCCESS'
};

console.log(JSON.stringify(logEntry));

// Continue to next practice in batch
return [{ json: logEntry }];

const allLogs = $input.all().map(item => item.json);

const summary = {
  timestamp: new Date().toISOString(),
  workflow: 'IPA athena FHIR Sync',
  ehr: 'athenahealth',
  totalPractices: allLogs.length,
  successfulPractices: allLogs.filter(l => l.status === 'SUCCESS').length,
  failedPractices: allLogs.filter(l => l.status === 'ERROR').length,
  totalBundles: allLogs.reduce((sum, l) => sum + (l.bundlesUploaded || 0), 0),
  practices: allLogs
};

return [{ json: summary }];
